import React, { useState } from 'react';

const s = {
  page: {
    minHeight: 'calc(100vh - 64px)',
    background: '#f3f4f6',
    padding: '40px 24px',
  },
  container: {
    maxWidth: 1280,
    margin: '0 auto',
  },
  title: {
    fontSize: 28,
    fontWeight: 700,
    color: '#111827',
    marginBottom: 24,
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: '1fr 2fr',
    gap: 24,
  },
  card: {
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: 10,
    padding: 24,
    boxShadow: '0 1px 3px rgba(0,0,0,0.07)',
  },
  scoreSection: {
    textAlign: 'center',
  },
  scoreNumber: {
    fontSize: 64,
    fontWeight: 700,
    color: '#2563eb',
    marginBottom: 12,
  },
  scoreLabel: {
    fontSize: 14,
    color: '#6b7280',
    marginBottom: 24,
  },
  skillsList: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: 8,
  },
  skillTag: {
    background: '#eff6ff',
    border: '1px solid #bfdbfe',
    color: '#1e40af',
    padding: '6px 12px',
    borderRadius: 20,
    fontSize: 12,
    fontWeight: 500,
  },
  candidateList: {
    display: 'flex',
    flexDirection: 'column',
    gap: 12,
  },
  candidateCard: (rank) => ({
    background: rank === 1 ? '#fef3c7' : '#fff',
    border: `1px solid ${rank === 1 ? '#fcd34d' : '#e5e7eb'}`,
    borderRadius: 8,
    padding: 16,
    cursor: 'pointer',
    transition: 'all 0.2s',
    ':hover': { boxShadow: '0 4px 6px rgba(0,0,0,0.1)' },
  }),
  candidateName: {
    fontSize: 14,
    fontWeight: 600,
    color: '#1f2937',
    marginBottom: 8,
  },
  candidateScore: (score) => ({
    fontSize: 20,
    fontWeight: 700,
    color: score >= 70 ? '#16a34a' : score >= 40 ? '#d97706' : '#dc2626',
  }),
  emptyState: {
    textAlign: 'center',
    padding: '60px 20px',
    color: '#9ca3af',
  },
};

export default function CandidateDashboard({ candidates, currentUserEmail }) {
  const [selectedCandidate, setSelectedCandidate] = useState(null);

  // Find current user's candidate info
  const userCandidate = candidates.find(c => c.email === currentUserEmail || c.email === 'user@example.com');
  
  // Get other candidates
  const otherCandidates = candidates.filter(c => c !== userCandidate).sort((a, b) => b.final_score - a.final_score);

  if (!userCandidate) {
    return (
      <div style={s.page}>
        <div style={s.container}>
          <div style={s.emptyState}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>👤</div>
            <h2 style={{ fontSize: 18, marginBottom: 8 }}>No Candidate Profile Found</h2>
            <p>Upload your resume first in the Recruiter section to see your profile.</p>
          </div>
        </div>
      </div>
    );
  }

  const selected = selectedCandidate || otherCandidates[0];

  return (
    <div style={s.page}>
      <div style={s.container}>
        <h1 style={s.title}>👤 Candidate Dashboard</h1>

        <div style={s.grid}>
          {/* Your Profile */}
          <div style={s.card}>
            <div style={s.scoreSection}>
              <div style={{ fontSize: 14, color: '#6b7280', marginBottom: 16, fontWeight: 500 }}>YOUR PROFILE</div>
              <div style={s.scoreNumber}>{userCandidate.final_score || 0}%</div>
              <div style={s.scoreLabel}>Overall Match Score</div>
              
              <div style={{ marginTop: 24 }}>
                <div style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 12, textAlign: 'left' }}>
                  ✓ YOUR MATCHED SKILLS ({userCandidate.matched_skills?.length || 0})
                </div>
                <div style={s.skillsList}>
                  {userCandidate.matched_skills?.map(skill => (
                    <div key={skill} style={{ ...s.skillTag, background: '#d1fae5', border: '1px solid #a7f3d0', color: '#065f46' }}>
                      {skill}
                    </div>
                  ))}
                </div>
              </div>

              {userCandidate.bonus_skills?.length > 0 && (
                <div style={{ marginTop: 16 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 12, textAlign: 'left' }}>
                    ⭐ BONUS SKILLS ({userCandidate.bonus_skills?.length || 0})
                  </div>
                  <div style={s.skillsList}>
                    {userCandidate.bonus_skills?.map(skill => (
                      <div key={skill} style={s.skillTag}>
                        {skill}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Other Candidates */}
          <div>
            <div style={{ ...s.card, marginBottom: 16 }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 12, textTransform: 'uppercase' }}>
                📊 Other Candidates ({otherCandidates.length})
              </div>
              <div style={s.candidateList}>
                {otherCandidates.map((c, i) => (
                  <div key={i} style={s.candidateCard(c.rank)}>
                    <div style={s.candidateName}>
                      #{c.rank} - {c.name || 'Unknown'}
                    </div>
                    <div style={s.candidateScore(c.final_score)}>{c.final_score}%</div>
                    <div style={{ fontSize: 11, color: '#6b7280', marginTop: 8 }}>
                      {c.matched_skills?.length || 0} matched skills
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Selected Candidate Details */}
            {selected && selected !== userCandidate && (
              <div style={s.card}>
                <div style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 16, textTransform: 'uppercase' }}>
                  📋 Candidate #{selected.rank} Details
                </div>
                <div style={s.candidateName}>{selected.name}</div>
                <div style={{ fontSize: 24, fontWeight: 700, color: '#e8440a', marginBottom: 16 }}>
                  {selected.final_score}%
                </div>
                
                <div style={{ marginBottom: 16 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 8 }}>Matched Skills</div>
                  <div style={s.skillsList}>
                    {selected.matched_skills?.map(skill => (
                      <div key={skill} style={{ ...s.skillTag, background: '#d1fae5', border: '1px solid #a7f3d0', color: '#065f46' }}>
                        {skill}
                      </div>
                    ))}
                  </div>
                </div>

                {selected.bonus_skills?.length > 0 && (
                  <div>
                    <div style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 8 }}>Bonus Skills</div>
                    <div style={s.skillsList}>
                      {selected.bonus_skills?.map(skill => (
                        <div key={skill} style={s.skillTag}>
                          {skill}
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
